Here's a modern MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = CreateFetcher(handler);

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Cancelled_ThrowsTaskCanceledException()
    {
        // Arrange — handler delays so cancellation fires first
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = CreateFetcher(handler);

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CooperativeTimeout_CancelsViaTestContext()
    {
        // The [Timeout] fires TestContext.CancellationToken, which propagates
        // into FetchAsync — verifying the method respects it.
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    /// <summary>Minimal test double for HttpMessageHandler.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<CancellationToken, Task<HttpResponseMessage>> _factory;

        public FakeHandler(HttpResponseMessage response)
            => _factory = _ => Task.FromResult(response);

        public FakeHandler(Func<CancellationToken, Task<HttpResponseMessage>> factory)
            => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _factory(cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` class | Performance + design clarity |
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly, not aborted |
| `Assert.ThrowsExactlyAsync` | Validates exact exception type with a clear failure message |
| `Assert.ThrowsAsync` | Used for cancellation since `TaskCanceledException` derives from `OperationCanceledException` |
| `FakeHandler` | Avoids mocking frameworks; gives full control over `HttpClient` behavior |

The cancellation test cancels the token *before* calling `FetchAsync`, while the cooperative timeout test lets `[Timeout(2000)]` cancel `TestContext.CancellationToken` naturally — proving `FetchAsync` properly propagates the token.
